import React, { useEffect } from "react";
import { contactAPI } from "../api/api";
import { formatDateRange, injectThemeVars } from "./utils/templateHelpers";

const STYLE_ID = "startupfounder-template-styles";
const FONT_ID = "startupfounder-template-font";
const css = `
.startupfounder-root{background:var(--color-bg);color:var(--color-text);min-height:100vh;font-family:var(--font-main),Syne,sans-serif}.startupfounder-root *{box-sizing:border-box}.startupfounder-shell{max-width:1220px;margin:0 auto;padding:28px 22px 48px}.startupfounder-top{display:flex;justify-content:space-between;align-items:center;gap:16px}.startupfounder-nav{display:flex;gap:16px;flex-wrap:wrap}.startupfounder-nav button{background:none;border:none;color:var(--color-text);font:inherit;cursor:pointer;opacity:.8}.startupfounder-hero{min-height:82vh;display:grid;grid-template-columns:1.1fr .9fr;gap:22px;align-items:end}.startupfounder-kicker{font-size:.82rem;letter-spacing:.24em;text-transform:uppercase;color:var(--color-accent)}.startupfounder-title{font-size:clamp(3.4rem,8vw,7rem);line-height:.88;margin:.45rem 0 0;font-weight:800;max-width:760px;color:#f8f3ec;text-shadow:0 12px 28px rgba(0,0,0,.28)}.startupfounder-copy{max-width:620px;color:rgba(248,243,236,.78);line-height:1.8}.startupfounder-actions{display:flex;gap:12px;flex-wrap:wrap;margin-top:22px}.startupfounder-btn{padding:12px 16px;border-radius:999px;border:none;font-weight:700;cursor:pointer}.startupfounder-btn.primary{background:var(--color-accent);color:#120c08}.startupfounder-btn.secondary{background:rgba(255,255,255,.06);color:var(--color-text);border:1px solid rgba(255,255,255,.1)}.startupfounder-metrics{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.startupfounder-metric,.startupfounder-card{border:1px solid rgba(255,255,255,.08);border-radius:26px;padding:20px;background:rgba(255,255,255,.03)}.startupfounder-metric strong{display:block;font-size:2rem;color:var(--color-accent)}.startupfounder-section{margin-top:26px}.startupfounder-section h2{font-size:.9rem;letter-spacing:.22em;text-transform:uppercase;color:rgba(248,243,236,.6);margin:0 0 14px}.startupfounder-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.startupfounder-contact{display:grid;grid-template-columns:1fr 420px;gap:18px}.startupfounder-contact form{display:grid;gap:12px}.startupfounder-contact input,.startupfounder-contact textarea{width:100%;padding:14px 16px;border-radius:16px;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.03);color:var(--color-text);font:inherit}.startupfounder-contact button{padding:12px 16px;border:none;border-radius:999px;background:var(--color-accent);color:#160d08;font-weight:800;cursor:pointer}@media (max-width:980px){.startupfounder-hero,.startupfounder-grid,.startupfounder-contact{grid-template-columns:1fr}.startupfounder-metrics{grid-template-columns:1fr}}
`;
function scrollToSection(id){const node=document.getElementById(id); if(node) node.scrollIntoView({behavior:"smooth",block:"start"});}
export default function StartupFounderTemplate({ portfolio }) {
  const profile = portfolio?.profile || {};
  const sections = portfolio?.sections || {};
  const style = injectThemeVars(portfolio?.themeData || {});
  useEffect(() => { if (!document.getElementById(STYLE_ID)) { const s=document.createElement("style"); s.id=STYLE_ID; s.textContent=css; document.head.appendChild(s);} if (!document.getElementById(FONT_ID)) { const l=document.createElement("link"); l.id=FONT_ID; l.rel="stylesheet"; l.href="https://fonts.googleapis.com/css2?family=Syne:wght@500;700;800&display=swap"; document.head.appendChild(l);} }, []);
  const submitContact = async (event) => { event.preventDefault(); const form = new FormData(event.currentTarget); try { await contactAPI.submit({ resumeId: portfolio?.resumeId, senderName: form.get("senderName"), senderEmail: form.get("senderEmail"), senderPhone: form.get("senderPhone"), subject: form.get("subject"), message: form.get("message") }); event.currentTarget.reset(); } catch (error) { console.error(error); } };
  return <div className="startupfounder-root" style={style}><div className="startupfounder-shell"><div className="startupfounder-top"><div className="startupfounder-kicker">Founder Portfolio</div><div className="startupfounder-nav"><button type="button" onClick={() => scrollToSection("projects")}>Projects</button><button type="button" onClick={() => scrollToSection("experience")}>Experience</button><button type="button" onClick={() => scrollToSection("contact")}>Contact</button></div></div><section className="startupfounder-hero"><div><h1 className="startupfounder-title">Build a founder story around traction, decisions, and signal.</h1><p className="startupfounder-copy">{profile.bio || "A bold portfolio system for founders, operators, and product leaders who need a stronger public narrative than a standard resume can provide."}</p><div className="startupfounder-actions"><button type="button" className="startupfounder-btn primary" onClick={() => scrollToSection("projects")}>See Product Work</button><button type="button" className="startupfounder-btn secondary" onClick={() => scrollToSection("contact")}>Get in Touch</button></div></div><div className="startupfounder-metrics">{[{ value: "12M", label: "Users reached" }, { value: "37%", label: "Activation lift" }, { value: "4x", label: "Revenue growth" }].map((item) => <div className="startupfounder-metric" key={item.label}><strong>{item.value}</strong><span>{item.label}</span></div>)}</div></section><section className="startupfounder-section" id="projects"><h2>Flagship Projects</h2><div className="startupfounder-grid">{(sections.projects || []).map((project, index) => <div className="startupfounder-card" key={project.id || index}><div className="startupfounder-kicker">Launch</div><h3 style={{ fontSize: "1.5rem", marginBottom: 8 }}>{project.title}</h3><p style={{ color: "rgba(248,243,236,.72)", lineHeight: 1.7 }}>{project.description || project.summary}</p></div>)}</div></section><section className="startupfounder-section" id="experience"><h2>Operator Experience</h2><div className="startupfounder-grid">{(sections.experience || []).map((item, index) => <div className="startupfounder-card" key={item.id || index}><div className="startupfounder-kicker">{formatDateRange(item.startDate || item.startYear, item.endDate || item.endYear, item.currentlyWorking)}</div><h3 style={{ marginBottom: 4 }}>{item.roleTitle || item.title}</h3><div style={{ color: "var(--color-accent)", marginBottom: 8 }}>{item.organizationName || item.company}</div><p style={{ color: "rgba(248,243,236,.72)", lineHeight: 1.7 }}>{item.roleDescription || item.description}</p></div>)}</div></section><section className="startupfounder-section" id="contact"><h2>Contact</h2><div className="startupfounder-contact"><div className="startupfounder-card"><h3 style={{ fontSize: "2rem", marginTop: 0 }}>Open to conversations about product, growth, and founder-led builds.</h3><p style={{ color: "rgba(248,243,236,.72)", lineHeight: 1.8 }}>{profile.email || "Reach out for advisory, speaking, or strategic collaboration."}</p></div><div className="startupfounder-card"><form onSubmit={submitContact}><input name="senderName" placeholder="Your name" required /><input name="senderEmail" type="email" placeholder="Your email" required /><input name="senderPhone" placeholder="Phone number" /><input name="subject" placeholder="What would you like to discuss?" required /><textarea name="message" rows="5" placeholder="Details" required /><button type="submit">Send message</button></form></div></div></section></div></div>;
}

